export type Cell = [number, number];

export function nextGeneration(cells: Cell[]): Cell[] {
  const key = (x: number, y: number) => `${x},${y}`;
  const liveSet = new Set(cells.map(([x, y]) => key(x, y)));

  const countNeighbors = (x: number, y: number): number => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (liveSet.has(key(x + dx, y + dy))) count++;
      }
    }
    return count;
  };

  const candidates = new Set<string>();
  const candidateCoords: Cell[] = [];
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        const nx = x + dx;
        const ny = y + dy;
        const k = key(nx, ny);
        if (!candidates.has(k)) {
          candidates.add(k);
          candidateCoords.push([nx, ny]);
        }
      }
    }
  }

  const result: Cell[] = [];
  for (const [x, y] of candidateCoords) {
    const n = countNeighbors(x, y);
    const alive = liveSet.has(key(x, y));
    if (alive && (n === 2 || n === 3)) result.push([x, y]);
    else if (!alive && n === 3) result.push([x, y]);
  }
  return result;
}

export type Cell = [number, number];

export function nextGeneration(cells: Cell[]): Cell[] {
  const key = (x: number, y: number) => `${x},${y}`;
  const liveSet = new Set(cells.map(([x, y]) => key(x, y)));

  const countNeighbors = (x: number, y: number): number => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (liveSet.has(key(x + dx, y + dy))) count++;
      }
    }
    return count;
  };

  const result: Cell[] = [];

  // Survivors first, preserving input order
  for (const [x, y] of cells) {
    const n = countNeighbors(x, y);
    if (n === 2 || n === 3) result.push([x, y]);
  }

  // Then newly born dead cells
  const seen = new Set<string>(cells.map(([x, y]) => key(x, y)));
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx;
        const ny = y + dy;
        const k = key(nx, ny);
        if (seen.has(k)) continue;
        seen.add(k);
        if (countNeighbors(nx, ny) === 3) result.push([nx, ny]);
      }
    }
  }

  return result;
}
